INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Electrical Drawing and BOM Release Process', 'electrical-drawing-and-bom-release-process', '<h2>Electrical Drawing and BOM Release Process</h2><p>This document is an internal engineering checklist used to verify that all approved submittal information has been properly reviewed, transferred, and incorporated into the final design package. It ensures key system features, electrical calculations, and component selections are confirmed and documented before the unit progresses further in the build process. The checklist functions as a coordination and validation step to maintain accuracy between approved drawings, specifications, and final engineering outputs.</p><h3>Review Approved Submittal Package</h3><ol><li>Review Customer Notes (if approved as noted).</li><li>Review deviations (if approved as noted).</li><li>Review Sales Order.</li><li>Review LLI cutsheets.</li><li>Cassette Type (Ex: IAT or Rotorsource).</li></ol><h3>Revision / File Control</h3><ol start="6"><li>Update revision and file reference from submittal draft.</li></ol><h3>Review Features</h3><ol start="7"><li>Reactivation Heat Type</li><li>Pre-Cooling Type (if applicable)</li><li>Pre-Heating Type (if applicable)</li><li>Post-Cooling Type (if applicable)</li><li>Post-Heating Type (if applicable)</li><li>Filter Monitoring Type (if applicable)</li><li>Dampers (if applicable)</li><li>Other</li></ol><h3>Job and Equipment Data</h3><ol start="15"><li>Reference Job #</li><li>Process Fan HP</li><li>React Fan HP</li></ol><h3>High Voltage Circuitry Verification</h3><ol start="18"><li>Apply FLA of high voltage components.</li><li>Calculate overcurrent protection of high voltage components.</li><li>Calculate wire size per high voltage component.</li><li>Calculate total FLA of unit.</li></ol><h3>Final Electrical / Documentation Checks</h3><ol start="22"><li>Update unit&apos;s FLA, MCA, and MOCP values on coverpage.</li><li>Check wire numbers and colors for accuracy.</li></ol>', 0, TRUE, 5
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'technical-training' AND m.slug = 'electrical-wiring-training'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'New York Blower Selection Process', 'new-york-blower-selection-process', '<h2>New York Blower Selection Process</h2><h3>Purpose</h3><p>Provide a standardized process for selecting the correct blower through the manufacturer&apos;s selection tool, validating performance and orientation, generating engineering files, and inserting the verified cut sheet into the project submittal package.</p><h3>Scope</h3><p>Use this procedure for any Innovative Air Technologies project requiring blower selection and documentation.</p><h3>Phase 1 &#8212; Determine Blower Type From System Design</h3><p><strong>1. Review the project flow diagram and equipment layout</strong></p><p>Before opening the selection software:</p><ul><li>Identify airflow direction</li><li>Determine where duct connections occur</li><li>Confirm fan placement within the system</li></ul><p><strong>2. Choose blower category based on design intent</strong></p><p>Typical blower types used:</p><p><strong>Backwards inclined square fans</strong></p><ul><li>Most common selection</li><li>Can discharge out the:<ul><li>Top</li><li>Front</li><li>Back</li></ul></li><li>Not ideal for bottom discharge due to installation difficulty</li></ul><p><strong>Plenum fans</strong></p><ul><li>Used when air is pushed directly into the system</li><li>Often used for:<ul><li>Bottom supply configurations</li><li>Open plenum air distribution</li></ul></li><li>May appear at the front of the unit</li></ul><p><strong>Compact fans</strong></p><ul><li>Rarely used</li><li>If required, consult manufacturer rep directly</li></ul><p><strong>Fan arrays</strong></p><ul><li>Not common</li><li>If needed, consult senior engineer or team member before selecting</li></ul><figure class="img-missing"><figcaption>&#128247; Image from Trainual: New York Blower selection software walkthrough video &#8212; re-upload via admin editor</figcaption></figure><h3>Phase 2 &#8212; Calculate Required Static Pressure</h3><p><strong>3. Perform system pressure drop calculation</strong></p><p>Use the internal Excel pressure-drop sheet.</p><p>Procedure:</p><ol><li>Start at the inlet of the system</li><li>Move left to right through the airflow path</li><li>Add the pressure drop for each component</li></ol><p>Examples of components with pressure loss:</p><ul><li>Inlet filters</li><li>Coils</li><li>Dampers</li><li>Heaters</li><li>Duct transitions</li><li>Silencers</li></ul><p><strong>4. Determine internal vs external static pressure</strong></p><p><strong>Internal static:</strong></p><ul><li>Pressure losses inside the equipment</li><li>Often calculated from component data</li></ul><p><strong>External static:</strong></p><ul><li>Pressure expected once the system is installed</li><li>Includes:<ul><li>Ductwork</li><li>Flexible hoses</li><li>Field routing</li></ul></li><li>Default IAT value is often 2 in. w.g.</li><li>May increase if specified by the customer (3&#8211;5 in. w.g. or more)</li></ul><p>Add internal + external values to determine total fan pressure requirement.</p><figure class="img-missing"><figcaption>&#128247; Image from Trainual: Excel pressure-drop calculation sheet video walkthrough &#8212; re-upload via admin editor</figcaption></figure><h3>Phase 3 &#8212; Confirm Fan Orientation and Rotation</h3><p><strong>5. Determine rotation direction</strong></p><p>Use the internal rotation reference sheet.</p><p>Important rule:</p><ul><li>Always interpret rotation looking at the back of the fan</li><li>Motor faces toward you when determining rotation</li></ul><p>Rotation options:</p><ul><li>Clockwise</li><li>Counter-clockwise</li></ul><p><strong>6. Determine discharge orientation</strong></p><p>Orientation depends on duct connection direction.</p><p>Example:</p><ul><li>Roof duct connection &#8594; Upward blast</li><li>Front duct connection &#8594; Front discharge</li><li>Rear duct connection &#8594; Rear discharge</li></ul><p>Match orientation to the system drawing before selection.</p><figure class="img-missing"><figcaption>&#128247; Image from Trainual: Fan orientation and rotation reference video &#8212; re-upload via admin editor</figcaption></figure><h3>Phase 4 &#8212; Enter Data Into Manufacturer Selection Tool</h3><p><strong>7. Open manufacturer product selection page</strong></p><p>Navigate to the New York Blower selection interface.</p><p><strong>8. Enter required airflow and pressure</strong></p><p>From the flow diagram:</p><ul><li>Airflow (CFM)</li><li>Total static pressure</li><li>Altitude (found on project documentation)</li><li>Operating temperature</li><li>Maximum temperature</li></ul><p>If winter conditions are not specified, leave winter fields at zero.</p><p><strong>9. Configure selection parameters</strong></p><p>Use the following defaults unless project specs say otherwise:</p><ul><li>Wheel type &#8594; Auto-select</li><li>Fan speed &#8594; Auto-select unless RPM limit specified</li><li>Wheel material &#8594; Default steel unless spark-resistant or corrosive conditions</li><li>Frequency &#8594; 60 Hz</li></ul><figure class="img-missing"><figcaption>&#128247; Image from Trainual: New York Blower software data entry video &#8212; re-upload via admin editor</figcaption></figure><h3>Phase 5 &#8212; Evaluate Selection Results</h3><p><strong>10. Compare results to sales or preliminary selections</strong></p><p>Check:</p><ul><li>Fan size</li><li>Horsepower</li><li>RPM</li><li>Static performance</li></ul><p>Try to stay close to preliminary selections if they exist.</p><p><strong>11. Exclude invalid options</strong></p><p>Reject any selection showing:</p><ul><li>Red performance warnings</li><li>Out-of-range conditions</li><li>Excessive speed or load</li></ul><p><strong>12. Choose optimal fan</strong></p><p>Selection priorities:</p><ol><li>Meets performance requirements</li><li>Smallest acceptable size</li><li>Lowest sound level</li><li>Reasonable power requirement</li><li>Economical construction (steel vs aluminum)</li></ol><p><strong>13. Open and review the cut sheet</strong></p><p>Click View to open the manufacturer cut sheet.</p><p>Verify:</p><ul><li>Airflow</li><li>Pressure</li><li>Motor size</li><li>Orientation</li><li>Rotation</li><li>Materials</li></ul><p>If acceptable, proceed.</p><figure class="img-missing"><figcaption>&#128247; Image from Trainual: Cut sheet review and verification video &#8212; re-upload via admin editor</figcaption></figure><h3>Phase 6 &#8212; Generate Engineering Package</h3><p><em>(This is the workflow from your earlier transcript, merged in)</em></p><p><strong>14. Open blower configuration window in the system model</strong></p><p>Confirm:</p><ul><li>Correct blower instance</li><li>Correct performance inputs</li></ul><p>Re-check:</p><ul><li>Horsepower</li><li>Static pressure</li><li>RPM</li><li>Airflow</li><li>Any system warnings</li></ul><p><strong>15. Generate drawing package</strong></p><p>Select Generate Drawing.</p><p>Allow time for the software to process multiple windows or tasks.</p><p><strong>16. Review optional configuration items</strong></p><p>Optional additions may include:</p><ul><li>Flanges</li><li>Mounting accessories</li><li>Assembly aids</li></ul><p>These are not always required but may improve installation or serviceability.</p><p><strong>17. Confirm configuration details</strong></p><p>Verify:</p><ul><li>Size</li><li>Fan classification</li><li>Arrangement</li><li>Orientation</li><li>Rotation</li></ul><p>Confirm they match:</p><ul><li>Flow diagram</li><li>System layout</li><li>Selection tool output</li></ul><p><strong>18. Confirm width / sizing</strong></p><p>If blower size is near a standard dimension (ex: ~97% width): consider rounding to a standard size to reduce cost and improve manufacturability.</p><p><strong>19. Select output files</strong></p><p>Ensure both are checked:</p><ul><li>PDF cut sheet</li><li>STEP file (for modeling validation)</li></ul><p><strong>20. Send the package</strong></p><p>Select Send Email / Generate Package.</p><p>System will:</p><ul><li>Queue request</li><li>Generate files</li><li>Email ZIP package</li></ul><p>This may take several minutes.</p><figure class="img-missing"><figcaption>&#128247; Image from Trainual: Generate engineering package video walkthrough &#8212; re-upload via admin editor</figcaption></figure><h3>Phase 7 &#8212; Validate Returned Files</h3><p><strong>21. Open ZIP package</strong></p><p>Check cut sheet PDF:</p><ul><li>Performance data</li><li>Orientation</li><li>Motor details</li></ul><p>Check STEP file:</p><ul><li>Confirm physical fit in assembly model if necessary</li></ul><p><strong>22. Final submittal step</strong></p><p>Drag the verified cut sheet into the project Submittal Package.</p><p>Blower selection and documentation process is now complete.</p>', 1, TRUE, 8
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'technical-training' AND m.slug = 'electrical-wiring-training'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Post-Cooling Coil Selection and Verification Process', 'post-cooling-coil-selection-and-verification-process', '<h2>Post-Cooling Coil Selection and Verification Process</h2><h3>Purpose</h3><p>This procedure outlines how to review a submitted post-cooling coil from the vendor, verify performance against design requirements, confirm physical fit and specifications, and approve the coil for ordering and BOM entry.</p><h3>When to Use This Procedure</h3><p>Use this process whenever:</p><ul><li>A vendor submits a post-cooling coil</li><li>A coil revision is received</li><li>A coil must be approved before ordering</li><li>A coil must be entered into the Bill of Materials</li></ul><h3>Step 1 &#8212; Verify Correct Vendor Submission</h3><p>Locate the coil documents in the project submittal package.</p><p>Typical submission includes:</p><ul><li>Vendor coil datasheet (often from Coilmaster)</li><li>Dimensional drawing</li><li>Performance output file</li></ul><p><strong>Confirm EasyCoil file matches vendor submission</strong></p><p>Open <strong>EasyCoil</strong> and compare it to the project folder.</p><p>Check:</p><ul><li>Job number matches</li><li>Model/configuration matches</li><li>Submission dates match</li></ul><p>If dates do not match:</p><ul><li>Identify the newest version</li><li>Always review the most recent submission</li></ul><h3>Step 2 &#8212; Verify Coil Performance Against Design</h3><p>Compare coil capacity. From the flow diagram, find the required cooling load.</p><p>Example:</p><ul><li>Required capacity: <strong>47,416 BTU</strong></li><li>Submitted coil: <strong>51.2 MBH</strong></li></ul><p>Acceptance rule: Submitted coil must provide <strong>equal or greater capacity</strong> than required.</p><p><strong>Verify entering and leaving air conditions</strong></p><p>Check:</p><ul><li>Entering dry bulb temperature</li><li>Entering humidity (grains or wet bulb)</li><li>Leaving dry bulb temperature</li></ul><p>If units differ:</p><ol><li>Open a psychrometric calculator</li><li>Convert values to match design units</li><li>Compare again</li></ol><p><strong>Correct mismatches if necessary</strong></p><p>If entering conditions are incorrect:</p><ol><li>Update values in EasyCoil</li><li>Re-run performance</li><li>Confirm capacity still meets requirements</li></ol><p>Re-running ensures:</p><ul><li>No hidden errors</li><li>Consistency between design and vendor data</li></ul><h3>Step 3 &#8212; Verify Coil Construction Details</h3><p>Check rows and fin density.</p><p>Typical guidelines:</p><p><strong>Pre-cooling coils</strong></p><ul><li>Aim for ~8 fins per inch</li><li>Avoid exceeding 10 FPI</li></ul><p><strong>Post-cooling coils</strong></p><ul><li>Typically <strong>12&#8211;14 fins per inch</strong></li><li>Auto-selection may default to 10 (acceptable in many cases)</li></ul><p><strong>Verify airflow velocity</strong></p><p>Preferred limits:</p><ul><li>Target: <strong>below 450 ft/min</strong></li><li>Maximum: <strong>500 ft/min</strong></li></ul><p>Higher velocity may cause:</p><ul><li>Moisture carryover</li><li>Higher pressure drop</li><li>Reduced efficiency</li></ul><p><strong>Verify air pressure drop</strong></p><p>Guidelines:</p><ul><li>Preferred: ~0.5 in. w.g.</li><li>Avoid exceeding <strong>1.0 in. w.g.</strong></li></ul><p>Higher pressure drop increases fan load and system inefficiency.</p><h3>Step 4 &#8212; Confirm Physical Fit</h3><p>Compare coil dimensions to unit drawing.</p><p>Verify:</p><ul><li>Width fits between cabinet framing</li><li>Height fits within cabinet limits</li><li>Length fits airflow path</li></ul><p>Outdoor units often allow more dimensional flexibility.</p><p><strong>Verify connection stubs</strong></p><p>Ensure:</p><ul><li>Minimum ~6 inches stub length</li><li>Adequate spacing from cabinet walls</li></ul><p>This prevents piping conflicts during installation.</p><p><strong>Confirm airflow direction and orientation</strong></p><p>Check:</p><ul><li>Coil airflow direction matches system flow</li><li>Connection stubs face correct piping side</li></ul><p>If reversed, adjust orientation in EasyCoil.</p><p><strong>Confirm fluid type</strong></p><p>Verify whether the coil uses:</p><ul><li>Water</li><li>Glycol mixture</li></ul><p>Ensure fluid matches design specifications.</p><p><strong>Check for special coatings</strong></p><p>Look for:</p><ul><li>Epoxy coatings</li><li>Corrosion-resistant finishes</li><li>Marine coatings</li></ul><p>If none are listed, assume standard construction.</p><h3>Step 5 &#8212; Generate Updated Vendor Files</h3><p>After making any corrections:</p><ol><li>In EasyCoil, right-click the coil</li><li>Select:<ul><li>Quotation</li><li>Performance</li><li>Add Drawing</li><li>Submit</li></ul></li></ol><p>This generates updated drawings and quote files.</p><p><strong>Archive prior versions</strong></p><p>Whenever a coil revision is made:</p><ol><li>Create a <strong>VOID</strong> folder</li><li>Move the previous version into it</li><li>Save the updated version in the main folder</li></ol><p>This preserves revision history.</p><h3>Step 6 &#8212; Internal Approval</h3><p><strong>Stamp vendor documents</strong></p><p>Apply internal approval stamp to the vendor PDF.</p><p><strong>Verify price is reasonable</strong></p><p>Quickly check pricing. If unsure:</p><ul><li>Compare against previous coil quotes</li><li>Ask purchasing for reference pricing</li></ul><p><strong>Document approval</strong></p><p>In the project folder, create a text file: <em>&quot;Approved to Order &#8211; [Initials + Date]&quot;</em></p><p>This confirms release authorization.</p><h3>Step 7 &#8212; Add Coil to Bill of Materials</h3><p><strong>Enter coil manually</strong></p><p>Coils are typically <strong>not stored in the database</strong>, so entry is manual.</p><p>Include:</p><ul><li>Manufacturer name</li><li>Model number</li><li>Capacity</li><li>Key specs or coatings if relevant</li></ul><p><strong>Confirm ordering classification</strong></p><p>Mark as:</p><ul><li>Production component</li><li>Not a spare part</li></ul><p>Once entered into the BOM, the coil approval process is complete.</p>', 2, TRUE, 7
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'technical-training' AND m.slug = 'electrical-wiring-training'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Selecting and Sizing the Desiccant Wheel — All Wheel Sizes 965x200 mm and Under (Non-Cassette)', 'selecting-and-sizing-the-desiccant-wheel-non-cassette', '<h2>Selecting and Sizing the Desiccant Wheel &#8212; All Wheel Sizes 965x200 mm and Under (Non-Cassette)</h2><h3>Purpose</h3><p>This procedure outlines how to size and select a desiccant wheel using the IIT calculator, verify performance values against the flow diagram, generate the wheel specification PDF, and enter the correct part into the Bill of Materials.</p><h3>When to Use This Procedure</h3><p>Use this process whenever:</p><ul><li>A new unit requires a desiccant wheel selection</li><li>Wheel sizing must be validated from calculations</li><li>Wheel documentation must be added to the job folder</li><li>A rotor must be added to the BOM</li></ul><h3>Step 1 &#8212; Verify Wheel Data on the Flow Diagram</h3><p>Locate the desiccant wheel section of the flow diagram.</p><p>Confirm the following information is present:</p><ul><li>Wheel size</li><li>Wheel speed</li><li>Process air entering conditions</li><li>Process air leaving conditions</li><li>Reactivation air entering conditions</li><li>Reactivation air leaving conditions</li></ul><p>If any of this information is missing: stop and contact Sales or Engineering before continuing. Missing data usually indicates an upstream calculation error.</p><h3>Step 2 &#8212; Enter Data Into IIT Wheel Calculator</h3><p>Open the <strong>IIT calculator</strong> and navigate to the desiccant wheel input section.</p><p>The calculator contains two columns:</p><ul><li><strong>Process air (left column)</strong></li><li><strong>Reactivation air (right column)</strong></li></ul><p><strong>Enter process air conditions</strong></p><p>From the flow diagram, input:</p><ul><li>Airflow (CFM)</li><li>Entering temperature (&#176;F)</li><li>Entering humidity (grains)</li></ul><p>Example from training:</p><ul><li>1000 CFM</li><li>60&#176;F</li><li>30.2 grains</li></ul><p><strong>Verify reactivation airflow</strong></p><p>The calculator automatically generates reactivation CFM. Compare it to the flow diagram.</p><p>If the values differ:</p><ul><li>Manually adjust the calculator value</li><li>Reactivation airflow commonly corresponds to a <strong>285&#176;F reactivation temperature</strong>, but may vary by project</li></ul><p><strong>Enter reactivation inlet humidity</strong></p><p>From the flow diagram, find the reactivation inlet grains value.</p><p>Example: 140.4 grains. Enter this into the calculator.</p><p><strong>Enter elevation</strong></p><p>Locate project altitude on the flow diagram.</p><p>Example: 1,000 ft elevation. Enter into calculator before running.</p><h3>Step 3 &#8212; Run the Calculation</h3><p>Click <strong>Calculate</strong>.</p><p>The calculator will generate:</p><ul><li>Wheel rotational speed</li><li>Process leaving conditions</li><li>Reactivation leaving conditions</li><li>Moisture removal performance</li></ul><h3>Step 4 &#8212; Verify Results Against Flow Diagram</h3><p>Compare calculator outputs to design values.</p><p><strong>Wheel speed:</strong> confirm rotations per hour match flow diagram.</p><p><strong>Process outlet conditions &#8212; verify:</strong></p><ul><li>Leaving dry bulb temperature</li><li>Leaving humidity (grains)</li><li>Airflow remains correct</li></ul><p><strong>Reactivation outlet conditions &#8212; verify:</strong></p><ul><li>Leaving temperature</li><li>Leaving grains</li></ul><p>If any values differ from the flow diagram: recheck inputs before continuing.</p><h3>Step 5 &#8212; Generate Wheel Specification Document</h3><p>Once results match:</p><ol><li>Click <strong>Download PDF</strong></li><li>Save the wheel specification file</li></ol><h3>Step 6 &#8212; Store Documentation in Job Folder</h3><p>Copy the PDF into the project folder.</p><p>Save location: <strong>Job Folder &#8594; Purchasing &#8594; Rotor</strong></p><p>This ensures Purchasing can access the correct wheel data.</p><h3>Step 7 &#8212; Determine Wheel Type (Cassette vs Standard Rotor)</h3><p>Check wheel diameter.</p><p>Rule:</p><ul><li>Wheels <strong>over 965 mm</strong> &#8594; Cassette rotor required</li><li>Wheels <strong>965 mm or smaller</strong> &#8594; Standard rotor</li></ul><p>Example from training: 550 mm wheel &#8594; Standard rotor (no cassette).</p><p>Cassette wheels require additional ordering forms.</p><h3>Step 8 &#8212; Add Wheel to Bill of Materials</h3><p>Locate the rotor size from the calculation.</p><p>Example:</p><ul><li>550 mm diameter</li><li>200 mm depth</li></ul><p>Search the <strong>Master Parts List</strong> for the matching rotor.</p><p><strong>Select correct configuration</strong></p><p>Ensure the selected part:</p><ul><li>Matches diameter and depth</li><li>Includes flange if required</li></ul><p>Example: &#10003; 550 x 200 rotor <strong>with flange</strong></p><p><strong>Add to BOM</strong></p><ol><li>Copy the part number into the BOM</li><li>Confirm the correct part populates</li><li>Mark item as:<ul><li>Production component</li><li>Not a spare part</li></ul></li></ol><p>Once entered into the BOM, the wheel selection process is complete.</p>', 3, TRUE, 6
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'technical-training' AND m.slug = 'electrical-wiring-training'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Submittal Creation Process', 'submittal-creation-process', '<h2>Submittal Creation Process</h2><p>This section walks through the full workflow for creating a project submittal package, from initial document gathering through final assembly and release. The following pages break the process into three stages: preparing project information, organizing vendor selections and long-lead items, and assembling and verifying the final submittal. Together, these steps ensure each submittal is accurate, complete, and ready for customer review without delays or revisions.</p>', 4, TRUE, 2
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'technical-training' AND m.slug = 'electrical-wiring-training'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Submittal Creation — Project Setup and Document Gathering', 'submittal-creation-project-setup-and-document-gathering', '<h2>Submittal Creation &#8212; Project Setup and Document Gathering</h2><h3>Purpose</h3><p>This procedure explains how to start a submittal package, verify project information, and gather all required source documents before assembling the submittal.</p><h3>When to Use This Procedure</h3><p>Use this process when beginning a new unit submittal package after the sales order has been released.</p><h3>Step 1 &#8212; Review Sales Order and Customer Documents</h3><ol><li>Open the <strong>Sales Order</strong></li><li>Print or save a copy for reference</li><li>Review the document for:<ul><li>Unit configuration</li><li>Options selected</li><li>Notes or special instructions</li></ul></li></ol><h3>Step 2 &#8212; Review Customer PO Folder</h3><p>Navigate to the <strong>Customer PO folder</strong>.</p><p>Check for:</p><ul><li>Emails</li><li>Attachments</li><li>Clarifications from customer</li><li>Special requests or deviations</li></ul><p>This ensures no instructions were missed in the formal sales order.</p><h3>Step 3 &#8212; Confirm Scope Before Building Submittal</h3><p>Before continuing, confirm:</p><ul><li>Unit configuration is understood</li><li>Options match the order</li><li>Any special requirements are noted</li></ul><p>This prevents rebuilding the submittal later due to missed details.</p><h3>Step 4 &#8212; Begin Submittal Folder Organization</h3><p>Navigate to the project directory and verify:</p><ul><li>Submittal folder exists</li><li>Purchasing folder exists</li><li>Long-lead items folder exists</li></ul><p>Create missing folders if necessary.</p><p>Typical structure:</p><ul><li>Submittals</li><li>Purchasing</li><li>Long Leads</li><li>Vendor Documents</li></ul><p>Keeping structure consistent prevents confusion later.</p><h3>Step 5 &#8212; Collect Initial Vendor Documentation</h3><p>Gather any vendor materials already received, such as:</p><ul><li>Fan selections</li><li>Coil documents</li><li>Heater specs</li><li>Filter data</li><li>Control components</li></ul><p>Do not assemble the submittal yet &#8212; only gather files at this stage.</p>', 5, TRUE, 5
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'technical-training' AND m.slug = 'electrical-wiring-training'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Submittal Creation — Vendor Selections and LLI', 'submittal-creation-vendor-selections-and-lli', '<h2>Submittal Creation &#8212; Vendor Selections and LLI</h2><h3>Purpose</h3><p>This procedure explains how to process vendor selections, store documentation, and organize long-lead components before assembling the final submittal.</p><h3>When to Use This Procedure</h3><p>Use this process after component selections (fans, coils, etc.) have been generated.</p><h3>Step 1 &#8212; Save Vendor Selection Files</h3><p>When vendor files arrive via email:</p><ol><li>Download the attachment</li><li>Save it in the project folder</li></ol><p>Typical path: <strong>Purchasing &#8594; Long Leads &#8594; Component Name</strong></p><p>Example:</p><ul><li>Purchasing<ul><li>Long Leads<ul><li>Process Fan</li><li>Reactivation Fan</li></ul></li></ul></li></ul><h3>Step 2 &#8212; Organize Files by Component</h3><p>Create folders for each major component:</p><ul><li>Process fan</li><li>Reactivation fan</li><li>Desiccant wheel</li><li>Coils</li><li>Heaters</li></ul><p>Each component should have its own folder. This makes it easier for:</p><ul><li>Purchasing</li><li>Engineering</li><li>Production</li><li>Future revisions</li></ul><h3>Step 3 &#8212; Run Remaining Component Selections</h3><p>If any selections are outstanding:</p><ul><li>Complete process fan selection</li><li>Complete reactivation fan selection</li><li>Verify orientation and rotation match drawings</li><li>Save all outputs to their folders</li></ul><p>Always verify:</p><ul><li>Rotation</li><li>Orientation</li><li>Performance values</li></ul><p>before saving to the project folder.</p><h3>Step 4 &#8212; Confirm All Long-Lead Documents Are Present</h3><p>Before moving on, confirm you have:</p><ul><li>All fan cut sheets</li><li>Coil documentation</li><li>Wheel documentation</li><li>Any specialty vendor equipment</li></ul><p>Once these are gathered, the submittal assembly stage can begin.</p>', 6, TRUE, 5
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'technical-training' AND m.slug = 'electrical-wiring-training'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Submittal Creation — Final Assembly, Verification, and Release', 'submittal-creation-final-assembly-verification-and-release', '<h2>Submittal Creation &#8212; Final Assembly, Verification, and Release</h2><h3>Purpose</h3><p>This procedure explains how to assemble the submittal package, verify completeness, and prepare the submittal for release to the customer.</p><h3>When to Use This Procedure</h3><p>Use this process once all vendor documentation and component selections have been gathered.</p><h3>Step 1 &#8212; Assemble Submittal Documents</h3><p>Begin combining:</p><ul><li>Unit layout drawings</li><li>Vendor cut sheets</li><li>Component specs</li><li>Performance documentation</li></ul><p>Place them in logical order so the customer can easily follow the system.</p><p>Typical order:</p><ol><li>Unit overview drawing</li><li>Process airflow components</li><li>Reactivation airflow components</li><li>Long-lead vendor items</li><li>Supporting specifications</li></ol><h3>Step 2 &#8212; Perform Completeness Check</h3><p>Before releasing, confirm:</p><ul><li>Every ordered component appears in the submittal</li><li>No outdated vendor files are included</li><li>Orientation and airflow directions match drawings</li><li>Capacity values match design intent</li></ul><p>This is the most important step to avoid resubmittals.</p><h3>Step 3 &#8212; Final Naming and Saving</h3><p>Use consistent naming conventions.</p><p>Example: <strong>JobNumber_Unit_Submittal_v1.pdf</strong></p><p>Avoid unclear names such as:</p><ul><li>final.pdf</li><li>newfile.pdf</li><li>submittal2.pdf</li></ul><h3>Step 4 &#8212; Save to Correct Project Location</h3><p>Place the completed submittal in:</p><p><strong>Project Folder &#8594; Submittals &#8594; Issued</strong></p><p>This ensures everyone knows which version was sent to the customer.</p><h3>Step 5 &#8212; Release Submittal</h3><p>Notify the responsible team member or project manager that:</p><ul><li>Submittal is complete</li><li>Files are stored correctly</li><li>Ready for customer transmission</li></ul><p>Once released, the submittal creation process is complete.</p>', 7, TRUE, 5
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'technical-training' AND m.slug = 'electrical-wiring-training'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Where to Save As-Built Drawings on OneDrive', 'where-to-save-as-built-drawings-on-onedrive', '<h2>Where to Save As-Built Drawings on OneDrive</h2><h3>1. Open the Project Folder</h3><p>Go to the project folder in <strong>OneDrive</strong>:</p><p><strong>Elec Drawings &amp; BOM &#8594; Projects &#8594; [Project Number]</strong></p><p>Example: <code>Elec Drawings &amp; BOM &#8594; Projects &#8594; 4329 (480-3-60)</code></p><h3>2. Create the As-Built Folder</h3><p>Inside the project folder:</p><ol><li>Click the <strong>+ (New)</strong> button</li><li>Select <strong>Folder</strong></li><li>Name the folder: <strong>00 &#8211; As-Built</strong></li></ol><p><em>Note: The &quot;00&quot; keeps the folder organized at the top of the project.</em></p><figure class="img-missing"><figcaption>&#128247; Image from Trainual: OneDrive folder structure example &#8212; re-upload via admin editor</figcaption></figure><h3>3. Upload the As-Built Drawings</h3><p>Open the <strong>00 &#8211; As-Built</strong> folder and upload the final drawings.</p><p>These drawings should be the latest revisions reflecting the <strong>final conditions prior to shipment or field work is complete</strong>.</p><blockquote><p><strong>Important:</strong> Only place <strong>final As-Built drawings</strong> in the <strong>00 &#8211; As-Built</strong> folder.</p></blockquote>', 8, TRUE, 3
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'technical-training' AND m.slug = 'electrical-wiring-training'
ON CONFLICT (module_id, slug) DO NOTHING;

-- ── Lessons: Engineering ──
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Engineering Training Program', 'engineering-training-program', '<h2>Engineering Training Program</h2><p>This training program has been developed to create a consistent, scalable foundation for engineering knowledge across our organization. As our products, processes, and team continue to grow, it is critical that we maintain a clear and repeatable way to transfer knowledge, develop skills, and ensure alignment across all engineering functions.</p><p>The goal of this program is not only to train new team members, but to provide a centralized resource that supports ongoing development, cross-training, and continuous improvement for the entire engineering team.</p><h3>What This Program Is Designed To Do</h3><ul><li>Standardize how engineering knowledge is documented and shared</li><li>Provide clear training pathways for new and existing team members</li><li>Improve consistency between engineering, manufacturing, and field performance</li><li>Capture and retain institutional knowledge that would otherwise be lost over time</li><li>Support long-term growth and scalability of the engineering department</li></ul><h3>How This Training Is Structured</h3><p>This program is organized into key sections that reflect the core responsibilities and knowledge areas of our engineering team.</p><ol><li><strong>Onboarding &amp; Foundations</strong> — Introduces fundamental concepts, terminology, and a high-level understanding of our systems and how they function.</li><li><strong>Core Product Knowledge</strong> — Covers the systems, components, and technologies that make up our dehumidification equipment, including both desiccant and refrigeration systems.</li><li><strong>Controls &amp; Electrical Systems</strong> — Focuses on how our units operate from a controls and electrical standpoint, including sensors, control logic, and system integration.</li><li><strong>Engineering Standards &amp; Processes</strong> — Outlines how engineering work is executed, including standards, documentation, submittals, and internal workflows.</li><li><strong>Manufacturing &amp; Production Integration</strong> — Explains how engineering decisions translate to the production floor and how we support manufacturing processes.</li><li><strong>Testing &amp; Validation</strong> — Defines how we verify performance, ensure quality, and troubleshoot issues during and after production.</li><li><strong>Advanced Engineering Topics</strong> — Dives deeper into specialized systems, components, and advanced concepts used in our equipment.</li><li><strong>Field Knowledge &amp; Applications</strong> — Connects engineering design to real-world applications, customer use cases, and field performance.</li><li><strong>Continuous Improvement &amp; Metrics</strong> — Captures lessons learned, post-production feedback, and performance metrics to drive ongoing improvement.</li><li><strong>Cross-Training &amp; Development</strong> — Supports long-term growth through skill development, cross-functional knowledge, and career progression.</li></ol><h3>Our Approach</h3><p>This is a living document. It is expected to evolve over time as new systems are introduced, processes improve, and additional knowledge is captured. Contributions and updates from the engineering team are not only encouraged — they are essential.</p><p>Our objective is simple:<br><strong>Build a system where knowledge is accessible, repeatable, and continuously improving.</strong></p>', 0, TRUE, 4
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'technical-training' AND m.slug = 'engineering'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Intro to Engineering at IAT', 'intro-to-engineering-at-iat', '<h2>Intro to Engineering at IAT</h2><p><em>Big Picture, Expectations, and How We Operate</em></p><h3>What Engineering Means at IAT</h3><p>At IAT, Engineering is responsible for designing, documenting, and supporting the systems that drive our dehumidification equipment. This includes everything from initial concept and system design to production support and field performance.</p><p><strong>Engineering does not operate in a vacuum. Our work directly impacts:</strong></p><ul><li>Manufacturing and how units are built</li><li>Quality and consistency across products</li><li>Field performance and customer satisfaction</li></ul><p><strong>Because of this, Engineering must balance:</strong></p><ul><li>Design accuracy</li><li>Practical buildability</li><li>System performance</li><li>Clear documentation</li></ul><h3>How Engineering Fits Into the Bigger Picture</h3><p><strong>Engineering sits in the middle of several key functions:</strong></p><ul><li>Sales / Applications &rarr; defines what the customer needs</li><li>Engineering &rarr; designs how it will work</li><li>Manufacturing &rarr; builds the system</li><li>Field Service &rarr; installs, maintains, and troubleshoots</li></ul><p><strong>A successful engineer at IAT understands that:</strong></p><ul><li>What is designed must be buildable</li><li>What is built must be serviceable</li><li>What is delivered must perform as expected</li></ul><h3>What We Actually Do (High-Level)</h3><p><strong>Engineering work at IAT typically includes:</strong></p><ul><li>Creating production drawings and documentation</li><li>Designing mechanical and electrical systems</li><li>Selecting components and materials</li><li>Developing sequences of operation (how the unit runs)</li><li>Supporting production during builds</li><li>Assisting with troubleshooting and field issues</li></ul><p>Every task should lead to one outcome: a system that works correctly, can be built efficiently, and performs in the field.</p><h3>Engineering Roles (Overview)</h3><p>Engineering at IAT is made up of multiple disciplines working together. [This section can be customized with current team members and roles]</p><p>Typical roles include:</p><ul><li>CAD Design</li><li>Mechanical Engineering</li><li>Electrical Engineering</li></ul><p>Each role has different responsibilities, but all contribute to the same final product.</p><h3>Key Principles We Work By</h3><p><strong>1. Build It So It Works</strong><br>Designs must function properly under real conditions — not just look good on paper.</p><p><strong>2. Build It So It Can Be Built</strong><br>If manufacturing cannot easily build it, the design needs to be improved.</p><p><strong>3. Document Everything Clearly</strong><br>Drawings, BOMs, and submittals must be accurate, complete, and easy to understand.</p><p><strong>4. Think Through the Full System</strong><br>Engineering is not just parts — it&apos;s how everything works together:</p><ul><li>Airflow</li><li>Refrigeration</li><li>Controls</li><li>Electrical</li></ul><p><strong>5. Own the Outcome</strong><br>Engineering is responsible for what gets released. That includes:</p><ul><li>Performance</li><li>Accuracy</li><li>Completeness</li></ul><h3>Expectations of an Engineer at IAT</h3><p><strong>Accountability</strong></p><ul><li>Take ownership of your work from start to finish</li><li>Ensure accuracy before releasing anything</li></ul><p><strong>Attention to Detail</strong></p><ul><li>Small mistakes in engineering can become big problems in production or the field</li></ul><p><strong>Communication</strong></p><ul><li>Work closely with manufacturing, other engineers, and leadership</li><li>Ask questions early to avoid issues later</li></ul><p><strong>Continuous Learning</strong></p><ul><li>Systems, controls, and standards will evolve</li><li>Engineers are expected to keep learning and improving</li></ul><p><strong>Support the Team</strong></p><ul><li>Help production when issues arise</li><li>Contribute to solutions, not just identify problems</li></ul><h3>How Training Is Structured</h3><p>This training program is designed to build engineering knowledge over time.</p><p><strong>Basic (0–3 Months)</strong></p><ul><li>Learn core concepts, systems, and documentation</li><li>Understand how engineering work flows</li></ul><p><strong>Intermediate (3–6 Months)</strong></p><ul><li>Expand into system design, controls, and product knowledge</li><li>Begin working more independently</li></ul><p><strong>Advanced (6–12 Months)</strong></p><ul><li>Handle more complex systems and problem-solving</li><li>Support production and field issues</li><li>Contribute to improvements and standards</li></ul><p><strong>Cross-Training (Ongoing)</strong></p><ul><li>Learn across disciplines (CAD, Mechanical, Electrical)</li><li>Build flexibility and depth within the team</li></ul><h3>Why This Training Exists</h3><p>The goal of this training program is to:</p><ul><li>Create consistency across the engineering team</li><li>Reduce errors and rework</li><li>Improve communication between departments</li><li>Build confident, capable engineers</li><li>Capture knowledge so it is not lost over time</li></ul><h3>Key Takeaway</h3><p>Engineering at IAT is not just about creating drawings or selecting parts. It is about <strong>designing systems that work, can be built, and perform in the real world</strong>.', 1, TRUE, 5
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'technical-training' AND m.slug = 'engineering'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Dehumidification 101', 'dehumidification-101', '<h2>Dehumidification 101</h2><p><em>What We&apos;re Actually Doing and Why It Matters</em></p><h3>What Is Dehumidification?</h3><p>Dehumidification is the process of removing moisture from the air.</p><p>Air always contains some level of water vapor. The amount of moisture in the air affects:</p><ul><li>Product quality</li><li>Equipment performance</li><li>Building conditions</li><li>Corrosion and mold growth</li></ul><p>At IAT, our goal is simple: <strong>Control moisture to a specific level so systems and processes can operate correctly.</strong></p><h3>Why Moisture Control Matters</h3><p>Too much moisture in the air can cause:</p><ul><li>Condensation on surfaces</li><li>Corrosion of equipment</li><li>Mold and microbial growth</li><li>Product defects (especially in sensitive environments)</li></ul><p>Too little moisture (in some cases) can also cause issues, such as:</p><ul><li>Static buildup</li><li>Material instability</li></ul><p>Engineering systems are designed to <strong>control moisture within a target range</strong>, not just remove it completely.</p><h3>How Moisture Exists in Air</h3><p>Air is made up of:</p><ul><li>Dry air (oxygen, nitrogen, etc.)</li><li>Water vapor (moisture)</li></ul><p>Key concepts:</p><ul><li><strong>Relative Humidity (RH)</strong> &rarr; How &ldquo;full&rdquo; the air is with moisture</li><li><strong>Dew Point</strong> &rarr; The temperature at which moisture begins to condense</li></ul><p>Lowering the dew point = removing moisture from the air.</p><p>Understanding these concepts is critical because systems are often designed around <strong>dew point targets</strong>, not just temperature.</p><h3>Two Main Ways to Remove Moisture</h3><p>At a high level, there are two primary methods:</p><p><strong>1. Refrigeration-Based Dehumidification</strong></p><p>This method removes moisture by <strong>cooling the air</strong>.</p><p><em>How it works:</em></p><ul><li>Air passes over a cold coil</li><li>Moisture condenses into liquid water</li><li>Water is drained away</li></ul><p><em>Best for:</em></p><ul><li>Moderate humidity levels</li><li>Comfort cooling environments</li></ul><p><em>Limitations:</em></p><ul><li>Less effective at very low humidity levels</li><li>Performance depends on temperature</li></ul><p><strong>2. Desiccant Dehumidification</strong></p><p>This method removes moisture using a <strong>desiccant material</strong> that absorbs water vapor.</p><p><em>How it works:</em></p><ul><li>Air passes through a desiccant wheel or media</li><li>Moisture is absorbed into the material</li><li>A separate airstream (regeneration air) removes the moisture from the desiccant</li></ul><p><em>Best for:</em></p><ul><li>Low humidity / low dew point applications</li><li>Industrial and process environments</li></ul><p><strong>Key Advantage:</strong> Works independently of temperature and can achieve much lower moisture levels.</p><h3>What Makes IAT Systems Different (High-Level)</h3><p>At IAT, we focus heavily on:</p><ul><li>Desiccant-based systems</li><li>Precise moisture control</li><li>Integration of multiple system types (desiccant + refrigeration + controls)</li></ul><p>Our systems are designed to:</p><ul><li>Maintain <strong>consistent conditions</strong></li><li>Handle <strong>industrial environments</strong></li><li>Deliver <strong>reliable long-term performance</strong></li></ul><h3>Key System Concepts You&apos;ll See Often</h3><p>As you go through training, you&apos;ll hear these terms frequently:</p><ul><li><strong>Process Air</strong> &rarr; The air being dried</li><li><strong>Regeneration Air</strong> &rarr; The air used to remove moisture from the desiccant</li><li><strong>Dew Point Control</strong> &rarr; Controlling moisture based on condensation temperature</li><li><strong>Airflow</strong> &rarr; Critical to system performance</li><li><strong>Load</strong> &rarr; The amount of moisture the system needs to remove</li></ul><p>These concepts are the foundation for understanding how our equipment operates.</p><h3>Where Engineering Comes In</h3><p>Engineering is responsible for:</p><ul><li>Designing systems to meet moisture targets</li><li>Selecting the correct dehumidification method</li><li>Ensuring airflow, temperature, and controls all work together</li><li>Supporting production and troubleshooting performance issues</li></ul><p>A good design must:</p><ul><li>Hit the required moisture levels</li><li>Be buildable in production</li><li>Perform reliably in the field</li></ul><h3>Common Misconceptions</h3><p><strong>&ldquo;Colder air always means drier air&rdquo;</strong><br>Not necessarily — cooling can remove moisture, but only to a point.</p><p><strong>&ldquo;Dehumidification is just removing water&rdquo;</strong><br>It&apos;s actually about <strong>controlling conditions</strong>, not just removing moisture.</p><p><strong>&ldquo;All systems work the same way&rdquo;</strong><br>Different applications require different approaches: Refrigeration vs Desiccant, High vs low dew point, Comfort vs industrial environments.</p><h3>Why This Matters for Your Role</h3><p>No matter your role (CAD, Mechanical, Electrical):</p><ul><li>You are contributing to a <strong>system designed to control moisture</strong></li><li>Small design decisions can impact Performance, Efficiency, and Reliability</li></ul><p>Understanding the basics of dehumidification will help you make better engineering decisions, troubleshoot issues more effectively, and communicate more clearly with the team.</p><h3>Key Takeaway</h3><p>Dehumidification is not just about removing moisture. It is about <strong>controlling the environment so systems, products, and processes can operate correctly and consistently</strong>.</p><p><em>(This page provides a foundational understanding. More detailed system operation, controls, and design considerations are covered in later sections.)</em></p>', 2, TRUE, 6
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'technical-training' AND m.slug = 'engineering'
ON CONFLICT (module_id, slug) DO NOTHING;
