SELECT m.id, 'Engineering Project Classification Guide', 'engineering-project-classification-guide', '<h2>Engineering Project Classification Guide</h2><p>We only use three project categories. If a project falls into a gray area, choose the category that most closely matches the overall engineering effort required.</p><h3>Std-Minor</h3><p>Minor changes to an existing master or previously completed unit.</p><p><strong>Typical Characteristics</strong></p><ul><li>Less than 20 parts modified</li><li>No framing changes or very minimal framing changes</li><li>Existing design remains mostly intact</li></ul><p><strong>Examples</strong></p><ul><li>Small component swaps</li><li>Minor layout adjustments</li><li>Small control or airflow changes</li></ul><h3>Std-Major</h3><p>An existing unit is available to work from, but major changes are required.</p><p><strong>Typical Characteristics</strong></p><ul><li>20+ parts modified</li><li>Framing changes required</li><li>Unit resizing</li><li>Significant layout or structural modifications</li></ul><p><strong>Examples</strong></p><ul><li>Resizing a unit</li><li>Major structural updates</li><li>Large redesigns from an existing platform</li></ul><h3>New</h3><p>A completely new design with significant R&amp;D effort.</p><p><strong>Typical Characteristics</strong></p><ul><li>Designed from scratch</li><li>No close existing reference unit</li><li>High uncertainty or development effort</li><li>New concepts or applications</li></ul><p><strong>Examples</strong></p><ul><li>Prototype designs</li><li>First-time applications</li><li>Custom one-off systems</li></ul><h3>Engineering Time by Project Type</h3><table><tr><th>Unit Size</th><th>Type</th><th>Avg. Actual Time</th><th>Scheduled Goal</th></tr><tr><td>&lt;5000 CFM</td><td>Std-Minor</td><td>13 hrs</td><td>3 days</td></tr><tr><td>&lt;5000 CFM</td><td>Std-Major</td><td>35 hrs</td><td>7 days</td></tr><tr><td>&lt;5000 CFM</td><td>New</td><td>31 hrs</td><td>N/A</td></tr><tr><td>5000+ CFM</td><td>Std-Minor</td><td>30 hrs</td><td>6 days</td></tr><tr><td>5000+ CFM</td><td>Std-Major/New</td><td>54 hrs</td><td>N/A</td></tr></table><h3>Notes</h3><ul><li>Scheduled goals are planning targets, not guarantees.</li><li>Actual timelines may vary depending on: Customer revisions, Engineering complexity, R&amp;D requirements, Resource availability</li></ul><blockquote>When uncertain: Pick the category that best represents the total engineering effort required.</blockquote>', 33, TRUE, 4
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'technical-training' AND m.slug = 'engineering'
