INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'How to Find Dewpoint to Determine Temp and Humidity Sensor Required', 'how-to-find-dewpoint-sensor-selection', '<h2>How to Find Dewpoint to Determine Temp &amp; Humidity Sensor Required</h2><p>Check if dewpoint process:</p><p>Go to IAT Calculator App: <a href="https://iatcalc.dehumidifiers.com/CalculatorApp">https://iatcalc.dehumidifiers.com/CalculatorApp</a></p><p>Select the Psychrometric button.</p><figure class="img-missing"><figcaption>&#128247; Image from Trainual: IAT Calculator App home screen showing the Psychrometric button highlighted among other calculator options including Moisture Removal, Air Mixing, Velocity/CFM, Btuh &amp; Kwh, Coil Widths-CV, React Heat, Weather Data, Desiccant Wheel Calculator, Ship Date Calculator, RPH/Time Calculator, Bypass CFM Calculator, Duct Diameter &amp; Friction Loss, Duct Diameter &amp; Velocity, Duct Velocity &amp; Friction Loss — re-upload via admin editor</figcaption></figure><p>Enter the Elevation, Temperature and Grains to get Dewpoint.</p><figure class="img-missing"><figcaption>&#128247; Image from Trainual: Psychrometric calculator interface showing input fields for Elevation (550), Volume (cubic inches), and Moisture (gr/lb = 29), with results displaying Volume, Temperature, Humidity, Wet Bulb, Dew Point (highlighted at -40.5), Humid. Ratio, Specific Vol., Air Density, Sat. Vapor Pressure — re-upload via admin editor</figcaption></figure><p>If &lt; -40F Td, select an ultra low dewpoint sensor. Example EE355 low dewpoint sensor.</p>', 71, TRUE, 3
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'technical-training' AND m.slug = 'engineering'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'SolidWorks Settings', 'solidworks-settings', '<h2>SolidWorks Settings</h2><p>This lesson covers the recommended SolidWorks system option settings for IAT engineering. The following settings panels should be configured as shown in the reference screenshots captured from the IAT standard setup.</p><figure class="img-missing"><figcaption>&#128247; Image from Trainual: SolidWorks System Options – General settings panel showing recommended checkbox configuration including Show thumbnails, Enable Confirmation Corner, Stop VSTA debugger on macro exit, Enable Freeze bar, and other general options — re-upload via admin editor</figcaption></figure><figure class="img-missing"><figcaption>&#128247; Image from Trainual: SolidWorks System Options – Drawings panel showing recommended settings including eliminate duplicate model dimensions on insert, maps all part/assembly dimensions for import, enable symbol when adding new revision, and other drawing defaults — re-upload via admin editor</figcaption></figure><figure class="img-missing"><figcaption>&#128247; Image from Trainual: SolidWorks System Options – Display Style panel showing recommended display style as Wireframe, edge quality for shaded views as High quality, tangent edges as Visible — re-upload via admin editor</figcaption></figure><figure class="img-missing"><figcaption>&#128247; Image from Trainual: SolidWorks System Options – Area Hatch/Fill panel showing Hatch selected with ANSI31 (Iron/BrkStl) pattern, scale 1, angle 0 — re-upload via admin editor</figcaption></figure><figure class="img-missing"><figcaption>&#128247; Image from Trainual: SolidWorks System Options – Performance panel showing recommended performance settings including show contents while dragging drawing views, allow auto-update when opening drawings, and sketch entity count threshold of 1000 — re-upload via admin editor</figcaption></figure><figure class="img-missing"><figcaption>&#128247; Image from Trainual: SolidWorks System Options – Colors panel showing color scheme Default, background light, selected items color configuration — re-upload via admin editor</figcaption></figure><figure class="img-missing"><figcaption>&#128247; Image from Trainual: SolidWorks System Options – Sketch panel showing Auto-rotate view normal to sketch plane on sketch creation, fully defined sketches, display entity points in different colors — re-upload via admin editor</figcaption></figure><figure class="img-missing"><figcaption>&#128247; Image from Trainual: SolidWorks System Options – Relations/Snaps panel showing enable snapping, snap to model geometry, automatic relations enabled, sketch snap options including endpoints, midpoints, center points, intersections, tangent, perpendicular, parallel, horizontal/vertical lines — re-upload via admin editor</figcaption></figure><figure class="img-missing"><figcaption>&#128247; Image from Trainual: SolidWorks System Options – Display panel showing hidden edges displayed as dashed, edge display in shaded with edges mode, use shaded face highlighting, show open edges of surfaces in different color, display reference triad — re-upload via admin editor</figcaption></figure><figure class="img-missing"><figcaption>&#128247; Image from Trainual: SolidWorks System Options – Selection panel showing default bulk selection method as Box, allow selection in wireframe and HLV modes, enhance small face selection precision — re-upload via admin editor</figcaption></figure><figure class="img-missing"><figcaption>&#128247; Image from Trainual: SolidWorks System Options – Performance panel (assembly mode) showing optimize for large assemblies, Large Assembly Settings options, envelope component settings — re-upload via admin editor</figcaption></figure><figure class="img-missing"><figcaption>&#128247; Image from Trainual: SolidWorks System Options – Assemblies panel showing move components by dragging, automatically place component when adding mates, save new components to external files, update model graphics when saving files — re-upload via admin editor</figcaption></figure><figure class="img-missing"><figcaption>&#128247; Image from Trainual: SolidWorks System Options – External References panel showing open referenced documents with read-only access, prompt to save read-only referenced documents on change, search external references in file location, update out-of-date linked design tables to prompt, automatically generate names for referenced geometry — re-upload via admin editor</figcaption></figure>', 72, TRUE, 5
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'technical-training' AND m.slug = 'engineering'
ON CONFLICT (module_id, slug) DO NOTHING;

