INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Checking AMPs/Connecting Power', 'checking-amps-connecting-power', '<h2>Checking AMPs/Connecting Power</h2><figure class="img-missing"><figcaption>📷 Image from Trainual: Photo of electrical panel with breaker and wiring — re-upload via admin editor</figcaption></figure><h3>Objective</h3><p>To ensure the safe and accurate testing of electrical power in units by verifying voltage levels at various points, preventing equipment damage, and ensuring proper functionality.</p><figure class="img-missing"><figcaption>📷 Image from Trainual: Embedded video — "Checking amps and connecting power" (4 min, 3 min 8 sec at 1.2x) — re-upload via admin editor</figcaption></figure><figure class="img-missing"><figcaption>📷 Image from Trainual: Photo showing electrical panel interior with yellow wiring and technician — re-upload via admin editor</figcaption></figure><h3>Procedure</h3><ol><li><strong>Preparation</strong><ul><li>Ensure you have the necessary tools: a multimeter, safety gloves, and safety goggles.</li><li>Familiarize yourself with the unit and its electrical components.</li></ul></li><li><strong>Power Check</strong><ul><li>Locate the main breaker and turn it on to ensure power is flowing.</li><li>Turn on the disconnect switch for the unit.</li></ul></li><li><strong>Voltage Measurement</strong><ul><li>Set the multimeter to measure alternating current (AC).</li><li>Check the voltage on the three legs of the power block:<ul><li>Each leg should read approximately 480 volts.</li><li>If any leg shows a different voltage, investigate potential wiring issues.</li></ul></li></ul></li><li><strong>Transformer Power Check</strong><ul><li>Inspect the transformer fuses to ensure they are functioning:<ul><li>Measure voltage at the top and bottom of the transformer fuses; both should read 490 volts.</li></ul></li><li>Confirm that power is being correctly transferred from 480 volts to approximately 120&ndash;130 volts.</li></ul></li><li><strong>Final Voltage Check</strong><ul><li>Turn on the control voltage power.</li><li>Set the multimeter to measure direct current (DC).</li><li>Measure the voltage at the bottom of the 24-volt transformer; it should read 24 volts.</li></ul></li><li><strong>Documentation</strong><ul><li>Record all voltage readings and any anomalies observed during the testing process for future reference.</li></ul></li></ol>', 4, TRUE, 5
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'technical-training' AND m.slug = 'testing-training'
ON CONFLICT (module_id, slug) DO NOTHING;
