INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Checking Motor Rotation', 'checking-motor-rotation', '<h2>Checking Motor Rotation</h2><h3>Objective</h3><p>To ensure that all motors are rotating in the correct direction prior to programming, which is critical for the proper functioning of the equipment.</p><figure class="img-missing"><figcaption>📷 Image from Trainual: Embedded video — "Motor Rotation Check" (5 min, 2 min 39 sec at 1.2x) — re-upload via admin editor</figcaption></figure><h3>Procedure</h3><ol><li><strong>Check the Process Motor:</strong><ul><li>Locate the process motor VFD (Variable Frequency Drive).</li><li>Increase the frequency using the knob until it reaches 6.75 Hz.</li><li>Press the Run button to activate the motor.</li><li>Observe the motor&apos;s rotation through the door. The fan should be turning counterclockwise.</li><li>Confirm that the direction is correct by checking the position of the duct, which should be on the left side of the wheel.</li><li>Turn off the motor and set the frequency back to 0 Hz.</li></ul></li><li><strong>Check the Rotor Wheel Direction:</strong><ul><li>Adjust the frequency knob to a higher setting, around 12 Hz.</li><li>Press the Run button to activate the rotor wheel.</li><li>Look for directional arrows on the wheel; ensure it is turning in the correct orientation as indicated by the arrow.</li><li>Turn off the rotor wheel after checking.</li></ul></li><li><strong>Check the React Motor:</strong><ul><li>Ensure the breaker for the react motor is turned on.</li><li>Manipulate the relay by opening the switch to activate the motor.</li><li>Since the motor spins quickly, turn it off and observe its direction quickly.</li><li>Confirm that the motor is rotating; it should always turn towards the plenum.</li></ul></li></ol>', 8, TRUE, 5
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'technical-training' AND m.slug = 'testing-training'
ON CONFLICT (module_id, slug) DO NOTHING;
