SELECT m.id, 'Unit Identification Sticker', 'unit-identification-sticker', '<h2>Unit Identification Sticker</h2><h3>Apply &ldquo;Unit Identification&rdquo; sticker to front left corner of unit</h3><p>Align your identification sticker with the etched marking on the front left of the unit, then firmly press down for secure placement.</p><blockquote>This sticker includes the unit serial number, model number, and company name.</blockquote><figure class="img-missing"><figcaption>📷 Image from Trainual: Unit identification sticker with serial number, model, and company name photo — re-upload via admin editor</figcaption></figure><figure class="img-missing"><figcaption>📷 Image from Trainual: Unit identification sticker applied to front left corner photo — re-upload via admin editor</figcaption></figure>', 15, TRUE, 1
